Load Balancer completo:

```hcl
resource "oci_load_balancer_load_balancer" "web" {
  compartment_id = var.compartment_ocid
  display_name   = "web-lb"
  shape_name     = "flexible"
  subnet_ids     = [oci_core_subnet.public.id]
  shape_details {
    minimum_bandwidth_in_mbps = 10
    maximum_bandwidth_in_mbps = 100
  }
}

resource "oci_load_balancer_backend_set" "backend" {
  load_balancer_id = oci_load_balancer_load_balancer.web.id
  name             = "web-backend"
  policy           = "ROUND_ROBIN"
  health_checker {
    protocol  = "HTTP"
    port      = 80
    url_path  = "/health"
  }
}

resource "oci_load_balancer_backend" "b1" {
  load_balancer_id = oci_load_balancer_load_balancer.web.id
  backendset_name  = oci_load_balancer_backend_set.backend.name
  ip_address       = oci_core_instance.web1.private_ip
  port             = 80
}

resource "oci_load_balancer_listener" "http" {
  load_balancer_id         = oci_load_balancer_load_balancer.web.id
  name                     = "http"
  default_backend_set_name = oci_load_balancer_backend_set.backend.name
  port                     = 80
  protocol                 = "HTTP"
}
```

Doc: https://registry.terraform.io/providers/oracle/oci/latest/docs

Path-based routing:

```hcl
resource "oci_load_balancer_backend_set" "api" {
  load_balancer_id = oci_load_balancer_load_balancer.web.id
  name             = "api-backend"
  policy           = "ROUND_ROBIN"
  health_checker { protocol = "HTTP"; port = 8080; url_path = "/api/health" }
}

resource "oci_load_balancer_backend_set" "web" {
  load_balancer_id = oci_load_balancer_load_balancer.web.id
  name             = "web-backend"
  policy           = "ROUND_ROBIN"
}

resource "oci_load_balancer_hostname" "api_host" {
  load_balancer_id = oci_load_balancer_load_balancer.web.id
  name             = "api-hostname"
  hostname         = "api.example.com"
  backend_set_name = oci_load_balancer_backend_set.api.name
}
```

/api/* → api-backend, /* → web-backend

Doc: https://registry.terraform.io/providers/oracle/oci/latest/docs

SSL com certificados gerenciados:

```hcl
resource "oci_certificate_certificate" "managed" {
  compartment_id   = var.compartment_ocid
  name             = "managed-web-cert"
  certificate_type = "MANAGED"
  certificate_config { algorithm = "RSA_2048" }
  subject { common_name = "www.example.com" }
}

resource "oci_load_balancer_listener" "https" {
  load_balancer_id = oci_load_balancer_load_balancer.web.id
  port             = 443
  protocol         = "HTTP"
  ssl_configuration {
    certificate_name = oci_certificate_certificate.managed.name
    protocols        = ["TLSv1.2", "TLSv1.3"]
  }
}
```

Vantagens: renovação automática, sem gerenciamento de arquivos

Doc: https://registry.terraform.io/providers/oracle/oci/latest/docs
